sql:
SELECT AVG(score) AS average_proficient_score
FROM student_assessment_results
WHERE proficiency_level = 'Proficient';

SELECT student_id, assessment_id
FROM student_assessment_results
WHERE score > 70;

SELECT category 
FROM student_demographics 
WHERE description = 'Students identifying as American Indian or Alaska Native';

SELECT score_id, valid_scores, students_with_proficiency
FROM student_scores
WHERE score_id > 0;

SELECT SUM(enrolled_students) 
FROM student_participation 
WHERE assessment_id = 0;

external_knowledge:
- "ocean of academic performance" refers to the comprehensive data on how students perform academically;
- "waves of success" represent the varying levels of success among students, measured by their average scores in assessments;
- "demographic reef" metaphorically represents the main demographic categories (e.g., American Indian or Alaska Native) in which students can be categorized;
- "submerged islands" refers to sub-categories within each main demographic category.

- 'sails' metaphorically represent demographic categories;
- 'dipped into the ocean of participation' is a metaphor for participation percentage;
- 'vast is their crew' refers to the number of enrolled students;
- 'shine with knowledge' is a metaphor for average scores.

sql:
SELECT enrolled_students, participating_students, participation_percentage
FROM student_participation
WHERE participation_id = 1;

SELECT year_name, description
FROM academic_years
WHERE year_id > 5;

SELECT AVG(score) AS average_score
FROM student_assessment_results
WHERE proficiency_level = 'Proficient';

SELECT participating_students, participation_percentage 
FROM student_participation 
WHERE academic_year_id = 1;
